message:
fix: safer Option::as_object_mut handling + simplify placeholder-override guard

Two small pickups from concurrent work in this tree:

* crates/mcp-agent-mail-cli/src/lib.rs
  - `fetch_mail_inbox_direct_with_database_url`: the `include_bodies`
    branch used `value.as_object_mut().unwrap().insert(...)`. Replace
    with `if let Some(obj) = value.as_object_mut() { obj.insert(...); }`.
    The JSON value is built from a `json!({ ... })` object literal a
    few lines up, so `as_object_mut()` is guaranteed to succeed
    today; the change just removes a panic point in case that
    construction ever grows a non-object alternative branch.

* crates/mcp-agent-mail-server/src/tui_screens/agents.rs
  - `enrich_lossy_agent_summary_rows_from_previous`: the branch that
    decides whether to adopt the previous-snapshot identity+project
    had two arms doing the same assignment with slightly different
    preconditions:
        if !previous.project.is_empty() && !previous_project_is_placeholder {
            row.identity = previous.identity.clone();
            row.project  = previous.project.clone();
        } else if row.project.is_empty() {
            row.identity = previous.identity.clone();
            row.project  = previous.project.clone();
        }
    Collapse to a single condition:
        if (non_empty_and_not_placeholder) || row.project.is_empty() {
            row.identity = previous.identity.clone();
            row.project  = previous.project.clone();
        }
    Semantics unchanged; fewer lines to audit against the backfill
    contract.

Not committed here:
  * crates/mcp-agent-mail-cli/src/e2e_runner.rs — still has the
    trailing-fragment corruption at EOF from a prior interrupted
    edit; leaving alone.
  * test_dir (scratch executable).

files.patch:
@@ -47607,10 +47607,12 @@ fn fetch_mail_inbox_direct_with_database_url(
             "thread_id": row.message.thread_id.clone(),
         });
         if include_bodies {
-            value.as_object_mut().unwrap().insert(
-                "body_md".to_string(),
-                serde_json::Value::String(row.message.body_md.clone()),
-            );
+            if let Some(obj) = value.as_object_mut() {
+                obj.insert(
+                    "body_md".to_string(),
+                    serde_json::Value::String(row.message.body_md.clone()),
+                );
+            }
         }
         data.push(value);
     }

@@ -348,10 +348,7 @@ fn enrich_lossy_agent_summary_rows_from_previous(
         // otherwise we'd just swap one placeholder for another.
         let previous_project_is_placeholder =
             previous.project.starts_with("[unknown-project-");
-        if !previous.project.is_empty() && !previous_project_is_placeholder {
-            row.identity = previous.identity.clone();
-            row.project = previous.project.clone();
-        } else if row.project.is_empty() {
+        if (!previous.project.is_empty() && !previous_project_is_placeholder) || row.project.is_empty() {
             row.identity = previous.identity.clone();
             row.project = previous.project.clone();
         }
